def step_impl(page):
    page.get_by_label('Email').fill('test@example.com')
    page.get_by_label('Password').fill('Secure@123')

@when(parsers.parse('the user fills the "{field_label}" field with "{value}"'))
def step_impl(page, field_label, value):
    page.get_by_label(field_label).fill(value)

