def step_impl(page, button_name):
    page.get_by_role('button', name=button_name).click()

@then(parsers.parse('the text "{expected_text}" should be visible on the page'))
def step_impl(page, expected_text):
    expect(page.get_by_text(expected_text)).to_be_visible()

